const sd = $getWorkflowStaticData('global');
if (sd.configValidated) {
  return [{ json: { ...$json, configCheckSkipped: true } }];
}
return [{ json: { ...$json, configCheckSkipped: false } }];

const sd = $getWorkflowStaticData('global');
sd.configValidated = true;
return [{ json: { ...$json, configCheckSkipped: true } }];

// Basic sanitization — owner-only mode reduces risk but defense-in-depth.
const sanitizeInput = (text) => {
  if (!text || typeof text !== 'string') return '';
  return text
    .slice(0, 2000)
    .replace(/\bIgnore (all )?previous instructions\b/gi, '[filtered]')
    .replace(/\bSystem:\s*You are\b/gi, '[filtered]')
    .replace(/\bACT AS\b/gi, '[filtered]')
    .trim();
};

const update = $input.item.json;
const isTelegram = !!update.message;
const isWebsite = !!update.body;

const traceId = () => {
  const base = 'sess_' + Date.now();
  const rand = Math.random().toString(36).slice(2, 8);
  return base + '_' + rand;
};

let result;
if (isTelegram) {
  const msg = update.message || update.callback_query?.message;
  const cbq = update.callback_query;
  result = {
    source: 'telegram',
    userId: String(msg?.from?.id || 'unknown'),
    sessionId: traceId(),
    messageId: String(msg?.message_id || ''),
    inputType: msg?.voice ? 'voice' : msg?.photo ? 'photo' : msg?.document ? 'document' : msg?.location ? 'location' : msg?.text ? 'text' : 'unknown',
    inputText: sanitizeInput(msg?.text || msg?.caption || cbq?.data || ''),
    inputFileId: msg?.voice?.file_id || (msg?.photo ? msg?.photo[msg.photo.length - 1]?.file_id : null) || msg?.document?.file_id || null,
    inputLocation: msg?.location ? { latitude: msg.location.latitude, longitude: msg.location.longitude } : null,
    metadata: {
      chatId: String(msg?.chat?.id || ''),
      replyEndpoint: null,
      timestamp: new Date().toISOString(),
      clientInfo: { firstName: msg?.from?.first_name, username: msg?.from?.username }
    }
  };
} else if (isWebsite) {
  const body = update.body || {};
  result = {
    source: 'website',
    userId: 'default',
    sessionId: body.session_id || traceId(),
    messageId: body.message_id || '',
    inputType: body.input_type || 'text',
    inputText: sanitizeInput(body.text || body.message || ''),
    inputFileId: null,
    inputLocation: body.location || null,
    metadata: {
      chatId: null,
      replyEndpoint: body.reply_url || null,
      timestamp: new Date().toISOString(),
      clientInfo: body.client_info || {}
    }
  };
} else {
  return [];
}

return [{ json: result }];

// Auth Gate: Validates owner identity and Telegram webhook secret.
// Telegram Trigger: n8n validates the secret_token automatically when configured
// in the node's 'Webhook URL' settings. No manual check needed for source='telegram'.
// Webhook: For website/webhook requests, $request.headers are available.

const OWNER_ID = String($env.OWNER_USER_ID || '');
const MODE = String($env.AUTH_MODE || 'open').toLowerCase();
const userId = String($json.userId || '');

if (MODE === 'protected' && OWNER_ID && userId !== OWNER_ID) {
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
      headers: { 'Content-Type': 'application/json' },
      body: { chat_id: $json.metadata?.chatId, text: '⛔ Access denied.' },
      timeout: 5000
    });
  } catch (e) {}
  return [];
}

return [$input.item];

const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) {
    console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](
      JSON.stringify({
        timestamp: new Date().toISOString(),
        level, traceId: $json.traceId || $json.sessionId || 'unknown',
        workflow: 'entry', message, meta
      })
    );
  }
};

const userId = String($json.userId || 'default');
const limit = parseInt($env.RATE_LIMIT_PER_MINUTE || '30', 10);
const MIN_INTERVAL_MS = 100;
const WINDOW_MS = 60_000;
const now = Date.now();

const sd = $getWorkflowStaticData('global');
if (!sd.rateLimits) sd.rateLimits = {};

const userTimestamps = (sd.rateLimits[userId] || [])
  .filter(ts => now - ts < WINDOW_MS);

if (userTimestamps.length >= limit) {
  jarvisLog('warn', 'Rate limit exceeded', { userId, count: userTimestamps.length, limit });
  throw new Error('RATE_LIMIT_EXCEEDED: ' + userTimestamps.length + '/' + limit + ' requests in last 60s');
}

if (userTimestamps.length > 0) {
  const lastTs = userTimestamps[userTimestamps.length - 1];
  if (now - lastTs < MIN_INTERVAL_MS) {
    jarvisLog('warn', 'Minimum inter-request delay not met', { userId, elapsed: now - lastTs });
    throw new Error('RATE_LIMIT_EXCEEDED: Too many rapid requests. Minimum 100ms between requests.');
  }
}

userTimestamps.push(now);
sd.rateLimits[userId] = userTimestamps;
return [{ json: { ...$json, startTime: now } }];
